using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor { ID = 10, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            SeedInstructors(context);
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 10 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 11 }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            SeedDepartments(context);
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
            );
            context.SaveChanges();
        }

        public static void SeedFull(SchoolContext context)
        {
            SeedCourses(context);
            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 2, CourseID = 4022, Grade = Grade.B }
            );
            context.CourseAssignments.AddRange(
                new CourseAssignment { InstructorID = 10, CourseID = 1050 },
                new CourseAssignment { InstructorID = 11, CourseID = 4022 }
            );
            context.OfficeAssignments.Add(
                new OfficeAssignment { InstructorID = 10, Location = "Smith 17" }
            );
            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.NotNull(result);
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(3, model!.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal("Alexander", model![0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal("Anand", model![0].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal("Alexander", model![0].LastName); // 2010
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal("Anand", model![0].LastName); // 2013
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SearchResetsPage()
        {
            var result = _controller.Index(null, null, "A", null) as ViewResult;
            // When searchString is not null, page resets to 1
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal(1, model!.PageIndex);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringNull()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            var result = _controller.Index("Date", null, "test", null) as ViewResult;
            Assert.Equal("Date", result!.ViewData["CurrentSort"]);
            Assert.Equal("date_desc", result.ViewData["DateSortParm"]);
            Assert.Equal("test", result.ViewData["CurrentFilter"]);
        }

        [Fact]
        public void Index_NameSortParm_EmptyWhenSortOrderSet()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            Assert.Equal("", result!.ViewData["NameSortParm"]);
        }

        [Fact]
        public void Index_NameSortParm_NameDescWhenDefault()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.Equal("name_desc", result!.ViewData["NameSortParm"]);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Add enrollment data for Include to work
            var result = _controller.Details(1) as ViewResult;
            Assert.NotNull(result);
            var student = result!.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student!.LastName);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var student = result!.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(DateTime.Today, student!.EnrollmentDate);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(student) as RedirectToActionResult;
            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_MinDateEnrollment_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_DateBeforeSqlRange_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

            _controller.Create(student);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(student) as ViewResult;
            Assert.NotNull(result);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1) as ViewResult;
            Assert.NotNull(result);
            var student = result!.Model as Student;
            Assert.Equal("Alexander", student!.LastName);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Updated",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            // Detach the tracked entity first
            var tracked = _context.Students.Find(1);
            _context.Entry(tracked!).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;
            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_Post_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = default
            };

            _controller.Edit(student);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            Assert.IsType<StatusCodeResult>(result);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1) as ViewResult;
            Assert.NotNull(result);
            var student = result!.Model as Student;
            Assert.Equal("Alexander", student!.LastName);
        }

        // --- Delete POST ---

        [Fact]
        public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;
            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(2, _context.Students.Count());
        }
    }
}

