using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain static queue to isolate tests
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain again to clean up
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification!.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.Contains("John Doe", notification!.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.Contains("42", notification!.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_HasCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Math", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.Contains("has been created", notification!.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_HasCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();
            Assert.Contains("has been updated", notification!.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_HasCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Math", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();
            Assert.Contains("has been deleted", notification!.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.True(notification!.CreatedAt >= before);
        }

        [Fact]
        public void SendNotification_SetsCreatedBy()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");
            var notification = _service.ReceiveNotification();
            Assert.Equal("Admin", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_DefaultUser_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_IsReadIsFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            Assert.False(notification!.IsRead);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNullWhenEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
        }

        [Fact]
        public void ReceiveNotification_DequeuedItemIsGone()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // No-op implementation, just verify it doesn't throw
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var svc = new NotificationService();
            var exception = Record.Exception(() => svc.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Dept", "5", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Dept", notification!.Message);
            Assert.Contains("5", notification.Message);
        }
    }
}

