using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedStudents(_context);
            _controller = new HomeController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentGroups()
        {
            var result = _controller.About() as ViewResult;
            Assert.NotNull(result);
            var model = result!.Model as List<EnrollmentDateGroup>;
            Assert.NotNull(model);
            // 3 students with 3 distinct dates (2010, 2012, 2013)
            Assert.Equal(3, model!.Count);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _controller.About() as ViewResult;
            var model = result!.Model as List<EnrollmentDateGroup>;
            // Meredith enrolled on same date, but she's the only one in 2012
            var group2012 = model!.First(g => g.EnrollmentDate?.Year == 2012);
            Assert.Equal(1, group2012.StudentCount);
        }

        [Fact]
        public void Contact_ReturnsViewWithMessage()
        {
            var result = _controller.Contact() as ViewResult;
            Assert.NotNull(result);
            Assert.Equal("Your contact page.", result!.ViewData["Message"]);
        }

        [Fact]
        public void Error_ReturnsView()
        {
            var result = _controller.Error();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;
            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", result!.ViewData["Message"]);
        }
    }
}

