using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanCreateContext()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context);
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestHelpers.CreateContext();
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };
            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestHelpers.CreateContext();
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.First();
            Assert.Equal("Instructor", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            using var context = TestHelpers.CreateContext();
            var dept = new Department
            {
                Name = "Test",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            Assert.Single(context.Departments);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            using var context = TestHelpers.CreateContext();
            var dept = new Department
            {
                Name = "Test",
                Budget = 100000,
                StartDate = DateTime.Now
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 100,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            Assert.Single(context.Courses);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            using var context = TestHelpers.CreateContext();
            TestHelpers.SeedFull(context);

            var ca = context.CourseAssignments.First();
            Assert.NotNull(ca);
        }

        [Fact]
        public void OfficeAssignment_LinkedToInstructor()
        {
            using var context = TestHelpers.CreateContext();
            TestHelpers.SeedFull(context);

            var oa = context.OfficeAssignments.Include(o => o.Instructor).First();
            Assert.NotNull(oa.Instructor);
            Assert.Equal("Smith 17", oa.Location);
        }

        [Fact]
        public void Enrollment_LinkedToCourseAndStudent()
        {
            using var context = TestHelpers.CreateContext();
            TestHelpers.SeedFull(context);

            var enrollment = context.Enrollments
                .Include(e => e.Course)
                .Include(e => e.Student)
                .First();

            Assert.NotNull(enrollment.Course);
            Assert.NotNull(enrollment.Student);
        }

        [Fact]
        public void Department_HasNavigationToAdministrator()
        {
            using var context = TestHelpers.CreateContext();
            TestHelpers.SeedDepartments(context);

            var dept = context.Departments.Include(d => d.Administrator).First();
            Assert.NotNull(dept.Administrator);
        }

        [Fact]
        public void DbSets_AreAccessible()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.People);
            Assert.NotNull(context.Notifications);
        }
    }
}

