using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3)
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void HasPreviousPage_TrueWhenPageIndexGreaterThan1()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_FalseWhenPageIndex1()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_TrueWhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage); // 2 pages total, on page 1
        }

        [Fact]
        public void HasNextPage_FalseWhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage); // 2 pages total, on page 2
        }

        [Fact]
        public void Create_FromQueryable_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]); // second page starts at 11
        }

        [Fact]
        public void Create_FirstPage_HasCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
        }

        [Fact]
        public void Create_LastPage_HasRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count); // only 5 items on last page
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Equal(0, list.TotalPages);

            var list2 = new PaginatedList<int>(new List<int>(), 1, 1, 10);
            Assert.Equal(1, list2.TotalPages);

            var list3 = new PaginatedList<int>(new List<int>(), 11, 1, 10);
            Assert.Equal(2, list3.TotalPages);
        }
    }
}

