using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_ReturnsLastCommaFirst()
        {
            var student = new Student { FirstMidName = "John", LastName = "Doe" };
            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsLastCommaFirst()
        {
            var instructor = new Instructor { FirstMidName = "Jane", LastName = "Smith" };
            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        [Fact]
        public void Student_HasEnrollments()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment> { new Enrollment(), new Enrollment() }
            };
            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Course_Properties()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
        }

        [Fact]
        public void Department_Properties()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000, dept.Budget);
            Assert.Equal(1, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_Nullable()
        {
            var dept = new Department { Name = "Test" };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Enrollment_GradeIsNullable()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_GradeValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        [Fact]
        public void CourseAssignment_Properties()
        {
            var ca = new CourseAssignment { InstructorID = 1, CourseID = 1050 };
            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
        }

        [Fact]
        public void OfficeAssignment_Properties()
        {
            var oa = new OfficeAssignment { InstructorID = 1, Location = "Room 101" };
            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Room 101", oa.Location);
        }

        [Fact]
        public void Notification_Properties()
        {
            var n = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };
            Assert.Equal(1, n.Id);
            Assert.Equal("Student", n.EntityType);
            Assert.False(n.IsRead);
            Assert.Null(n.ReadAt);
        }

        [Fact]
        public void EntityOperation_Values()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenSet()
        {
            var vm = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(vm.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenNull()
        {
            var vm = new ErrorViewModel();
            Assert.False(vm.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenEmpty()
        {
            var vm = new ErrorViewModel { RequestId = "" };
            Assert.False(vm.ShowRequestId);
        }

        [Fact]
        public void InstructorIndexData_Properties()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };
            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }

        [Fact]
        public void AssignedCourseData_Properties()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };
            Assert.Equal(1050, data.CourseID);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2020-01-01"),
                StudentCount = 5
            };
            Assert.Equal(5, group.StudentCount);
            Assert.NotNull(group.EnrollmentDate);
        }

        [Fact]
        public void EnrollmentDateGroup_NullableDate()
        {
            var group = new EnrollmentDateGroup();
            Assert.Null(group.EnrollmentDate);
        }
    }
}

